// Define environment schema
const envSchema = Type.Object({
  NODE_ENV: Type.String({ default: 'development' }),
  PORT: Type.Number({ default: 3000 }),
  HOST: Type.String({ default: '0.0.0.0' }),
  LOG_LEVEL: Type.String({ default: 'info' }),

  // Database
  DATABASE_URL: Type.String(),

  // Authentication
  JWT_SECRET: Type.String(),
  JWT_EXPIRES_IN: Type.String({ default: '7d' }),

  // API
  API_PREFIX: Type.String({ default: '/api' }),
  API_VERSION: Type.String({ default: 'v1' }),

  // Rate Limiting
  RATE_LIMIT_MAX: Type.Number({ default: 100 }),
  RATE_LIMIT_TIME_WINDOW: Type.Number({ default: 60000 }),

  // CORS
  CORS_ORIGIN: Type.String({ default: 'http://localhost:3001,http://localhost:3000' }),
  CORS_CREDENTIALS: Type.Boolean({ default: true }),

  // Monitoring
  METRICS_ENABLED: Type.Boolean({ default: true }),
  METRICS_PATH: Type.String({ default: '/metrics' }),

  // Swagger
  SWAGGER_ENABLED: Type.Boolean({ default: true }),
  SWAGGER_PATH: Type.String({ default: '/documentation' }),
});

export type Env = Static<typeof envSchema>;

// Extend Fastify instance type
declare module 'fastify' {
  interface FastifyInstance {
    config: Env;
  }
}

export default fp(
  async function envPlugin(fastify) {
    await fastify.register(fastifyEnv, {
      confKey: 'config',
      schema: envSchema,
      dotenv: true,
      data: process.env,
    });
  },
  {
    name: 'env',
  }
);

import { type FastifyPluginAsyncTypebox, Type } from '@fastify/type-provider-typebox'

const plugin: FastifyPluginAsyncTypebox = async function (fastify, _opts) {
  fastify.get('/', {
    schema: {
      tags: ['Hello World'],
      description: 'Salute someone via a GET call.',
      summary: 'GET Hello Route',
      querystring: Type.Object({
        name: Type.String({
          default: 'world',
          description: 'Pass the name of the person you want to salute.'
        })
      }),
      response: {
        200: Type.Object({
          hello: Type.String()

        })
      }
    }
  }, (req) => {
    const { name } = req.query
    return { hello: name }
  })

  fastify.post('/', {
    schema: {
      tags: ['Hello World'],
      description: 'Salute someone via a POST call.',
      summary: 'POST Hello Route',
      body: Type.Object({
        name: Type.Optional(Type.String())
      }, {
        description: 'Use the name property to pass the name of the person you want to salute.'
      }),
      response: {
        200: Type.Object({
          hello: Type.String()
        })
      }
    }
  }, async (request) => {
    const { name } = request.body
    const hello = typeof name !== 'undefined' && name !== '' ? name : 'world'

    return { hello }
  })
}

export default plugin

import fp from 'fastify-plugin';
import { FastifyInstance } from 'fastify';
import { Kysely, PostgresDialect, sql } from 'kysely';
import { Database } from '../modules/users/users.model';
import pg from 'pg';

async function databasePlugin(fastify: FastifyInstance) {
  const { config } = fastify;

  const dialect = new PostgresDialect({
    pool: new pg.Pool({
      host: config.DB_TEST_HOST || config.DB_HOST,
      port: config.DB_TEST_PORT || config.DB_PORT,
      user: config.DB_TEST_USER || config.DB_USER,
      password: config.DB_TEST_PASSWORD || config.DB_PASSWORD,
      database: config.DB_TEST_NAME || config.DB_NAME,
      max: config.DB_TEST_POOL_MAX || config.DB_POOL_MAX,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000
    })
  });

  const db = new Kysely<Database>({ dialect });

  try {
    await sql`SELECT 1`.execute(db);
    fastify.log.debug('Database connection health check passed');

    fastify.decorate('database', db);

    fastify.addHook('onClose', async () => {
      await db.destroy();
      fastify.log.info('Kysely Database connection pool closed');
    });
  } catch (error) {
    fastify.log.error('Database connection failed during startup');
    throw error;
  }
}

export default fp(databasePlugin, {
  name: 'database',
  dependencies: ['config']
});

import { Type } from '@sinclair/typebox';
import type { FastifyPluginAsyncTypebox } from '@fastify/type-provider-typebox';

const userRoutes: FastifyPluginAsyncTypebox = async (fastify) => {
  // Get current user
  fastify.get(
    '/me',
    {
      preValidation: [fastify.authenticate],
      schema: {
        description: 'Get current user profile',
        tags: ['Users'],
        security: [{ bearerAuth: [] }],
        response: {
          200: Type.Object({
            success: Type.Literal(true),
            data: Type.Object({
              id: Type.String(),
              email: Type.String(),
              name: Type.String(),
              role: Type.String(),
              createdAt: Type.String(),
              updatedAt: Type.String(),
            }),
          }),
        },
      },
    },
    async (request, reply) => {
      const user = await fastify.prisma.user.findUnique({
        where: { id: request.user.id },
        select: {
          id: true,
          email: true,
          name: true,
          role: true,
          createdAt: true,
          updatedAt: true,
        },
      });

      if (!user) {
        return reply.notFound('User not found');
      }

      return reply.send({
        success: true,
        data: {
          ...user,
          createdAt: user.createdAt.toISOString(),
          updatedAt: user.updatedAt.toISOString(),
        },
      });
    }
  );
};

export default userRoutes;

