import fastifyEnv from "@fastify/env";
import type { FastifyInstance, FastifyPluginCallback } from "fastify";
import fastifyPlugin from "fastify-plugin";
import { Static, Type } from "@sinclair/typebox";

enum NodeEnv {
  development = "development",
  test = "test",
  production = "production",
}

const ConfigSchema = Type.Strict(
  Type.Object({
    NODE_ENV: Type.Enum(NodeEnv),
    LOG_LEVEL: Type.String(),
    HTTP_PORT: Type.String(),
    HTTP_HOST: Type.String(),
    MONGO_URL: Type.String(),
    MONGO_DB_NAME: Type.String(),
    MONGO_COLLECTION_NAME: Type.String(),
  }),
);

type Config = Static<typeof ConfigSchema>;

declare module "fastify" {
  interface FastifyInstance {
    config: Config;
  }
}

const buildFastifyEnv: FastifyPluginCallback = async (
  server: FastifyInstance,
  options: Record<string, any>,
  done: (err?: Error | undefined) => void,
) => {
  const schema = {
    type: "object",
    required: [
      "HTTP_PORT",
      "HTTP_HOST",
      "MONGO_URL",
      "MONGO_DB_NAME",
      "MONGO_COLLECTION_NAME",
    ],
    properties: {
      HTTP_PORT: {
        type: "number",
        default: 3000,
      },
      HTTP_HOST: {
        type: "string",
        default: "0.0.0.0",
      },
      MONGO_URL: {
        type: "string",
      },
      MONGO_DB_NAME: {
        type: "string",
      },
      MONGO_COLLECTION_NAME: { type: "string" },
    },
  };

  const configOptions = {
    confKey: "config",
    schema: schema,
    data: process.env,
    dotenv: true,
    removeAdditional: true,
  };

  return fastifyEnv(server, configOptions, done);
};

export const buildFastifyEnvPlugin = fastifyPlugin(buildFastifyEnv);

import Fastify from 'fastify'
import mercurius from 'mercurius'

const app = Fastify({ logger: true })

let x = 0

const schema = `
  type ResultChange {
    operation: String
    prev: Int
    current: Int
  }
  type Query {
    result: Int
  }
  type Mutation {
    add(num: Int): Int
    subtract(num: Int): Int
  }
  type Subscription {
    onResultChange: ResultChange
  }
`

const resolvers = {
  Query: {
    result: async () => {
      return x
    }
  },
  Mutation: {
    add: async (_, args, { pubsub }) => {
      const prev = x
      const { num } = args

      x = prev + num

      pubsub.publish({
        topic: 'RESULT_TOPIC',
        payload: {
          onResultChange: {
            operation: 'add',
            prev,
            current: x
          }
        }
      })

      return x
    },
    subtract: async (_, args, { pubsub }) => {
      const prev = x
      const { num } = args

      x = prev - num

      pubsub.publish({
        topic: 'RESULT_TOPIC',
        payload: {
          onResultChange: {
            operation: 'subtract',
            prev,
            current: x
          }
        }
      })

      return x
    }
  },
  Subscription: {
    onResultChange: {
      subscribe: async (_, __, { pubsub }) => {
        return await pubsub.subscribe('RESULT_TOPIC')
      }
    }
  }
}

app.register(mercurius, {
  schema,
  resolvers,
  graphiql: true,
  subscription: {
    fullWsTransport: true
  }
})

app.listen({ port: 4000 })

